private int minTimeToDiffuseAll(int[] detonate, int[] diffuse, int n) {
    int time = 0;
    List<int[]> lst = new ArrayList<>();

    for (int i = 0; i < n; i++) {
        lst.add(new int[]{detonate[i], diffuse[i]});
    }

    // Sort by detonation time
    Collections.sort(lst, (a, b) -> a[0] - b[0]);

    for (int i = 0; i < n; i++) {
        int detTime = lst.get(i)[0];   // detonation time
        int defTime = lst.get(i)[1];   // defuse time

        if (time + defTime <= detTime) {
            time += defTime;
        } else {
            return -1; // bomb explodes
        }
    }

    return time;
}

